section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/php-laravel-patterns.json",
  "type": "object",
  "required": [
    "module",
    "fat_controllers",
    "inline_validation_count",
    "raw_model_response_count",
    "tx_in_controller_count",
    "policies_present"
  ],
  "properties": {
    "module": {
      "type": "string"
    },
    "fat_controllers": {
      "type": "integer",
      "maximum": 0,
      "description": "Controllers with any method >20 LoC"
    },
    "inline_validation_count": {
      "type": "integer",
      "maximum": 0
    },
    "raw_model_response_count": {
      "type": "integer",
      "maximum": 0
    },
    "tx_in_controller_count": {
      "type": "integer",
      "maximum": 0
    },
    "policies_present": {
      "type": "boolean",
      "const": true
    },
    "services_present": {
      "type": "boolean",
      "const": true
    }
  },
  "additionalProperties": false
}
